```class Solution {
public:
    long long countGoodIntegers(int n, int k) {
        long long res = 0;
        for (int i = 1; i <= k; i++) {
            for (int j = 0; j < n - 1; j++) {
                if (i * 10 + i == k) break;
                res += (k - i) * (k - i - 1) / 2;
            }
        }
        return res;
    }
};```
